const fs = require('fs');
const filePath = '/data/alertas_reaseguro.md';
const output = $('Agente de Triaje').item.json.output || '';
const now = new Date().toISOString().replace('T', ' ').substring(0, 19);
const polMatch = output.match(/PÓLIZA:\s*([^\n]+)/);
const poliza = polMatch ? polMatch[1].trim() : 'N/A';
const ramoMatch = output.match(/RAMO:\s*([^\n]+)/);
const ramo = ramoMatch ? ramoMatch[1].trim() : 'N/A';
const obsMatch = output.match(/OBSERVACIONES:\s*([^\n]+)/);
const obs = obsMatch ? obsMatch[1].trim() : '';
const row = `| ${now} | ${poliza} | ${ramo} | Alta | ${obs} |`;
if (!fs.existsSync(filePath)) {
  const header = '# Alertas Reaseguro\n\n| Fecha | Póliza | Ramo | Severidad | Observaciones |\n|-------|--------|------|-----------|---------------|\n';
  fs.writeFileSync(filePath, header);
}
fs.appendFileSync(filePath, row + '\n');
return [{ json: { output } }];

const fs = require('fs');
const filePath = '/data/log_triaje.md';
const output = $('Agente de Triaje').item.json.output || '';
const now = new Date().toISOString().replace('T', ' ').substring(0, 19);
const polMatch = output.match(/PÓLIZA:\s*([^\n]+)/);
const poliza = polMatch ? polMatch[1].trim() : 'N/A';
const sevMatch = output.match(/SEVERIDAD:\s*([^\n]+)/);
const severidad = sevMatch ? sevMatch[1].trim() : 'N/A';
const liqMatch = output.match(/LIQUIDADOR:\s*([^\n]+)/);
const liquidador = liqMatch ? liqMatch[1].trim() : 'N/A';
const row = `| ${now} | ${poliza} | ${severidad} | ${liquidador} |`;
if (!fs.existsSync(filePath)) {
  const header = '# Log de Triaje\n\n| Fecha | Póliza | Severidad | Liquidador |\n|-------|--------|-----------|------------|\n';
  fs.writeFileSync(filePath, header);
}
fs.appendFileSync(filePath, row + '\n');
return [{ json: { output } }];
